# upload the student details in a csv file and display the details in a table
import pandas as pd
import numpy as np

Student_details = st.file_uploader("Upload your details in a csv file", type=["csv"], key="student_details")
if Student_details is not None:
    df = pd.read_csv(Student_details)
    st.dataframe(df)